class Solution:
    def minNumberOfFrogs(self, croakOfFrogs: str) -> int:
        order = 'croak'
        pos = {c: i for i, c in enumerate(order)}
        count = [0] * 5
        ans = 0
        for ch in croakOfFrogs:
            if ch not in pos:
                return -1
            i = pos[ch]
            if i == 0:
                count[0] += 1
            else:
                if count[i-1] == 0:
                    return -1
                count[i-1] -= 1
                count[i] += 1
            if i == 4:
                # frog finished
                count[4] -= 1
            ans = max(ans, sum(count[:4]))  # active (not yet finished)
        if any(count[:4]):
            return -1
        return ans

