var minNumberOfFrogs = function(croakOfFrogs) {
    const order = 'croak';
    const idx = {};
    for (let i = 0; i < order.length; i++) idx[order[i]] = i;
    const stage = [0, 0, 0, 0, 0];
    let ans = 0;
    for (const ch of croakOfFrogs) {
        const i = idx[ch];
        if (i === 0) {
            stage[0]++;
        } else {
            if (stage[i-1] === 0) return -1;
            stage[i-1]--;
            stage[i]++;
        }
        if (i === 4) stage[4]--;
        ans = Math.max(ans, stage[0] + stage[1] + stage[2] + stage[3]);
    }
    return (stage[0] + stage[1] + stage[2] + stage[3]) > 0 ? -1 : ans;
};
